14|def parse_gcode(gcode_path: str) -> tuple[list[dict], dict]:
15|    """Parse G-code file and return moves + stats."""
16|    moves = []
17|    current_z = 0.0
18|    current_e = 0.0
19|    line_pat = re.compile(r'^(G[01])\s+(.*)')
20|
21|    with open(gcode_path) as f:
22|        for line in f:
23|            line = line.strip()
24|            if line.startswith(';') or not line:
25|                continue
26|            m = line_pat.match(line)
27|            if not m:
28|                continue
29|            cmd = m.group(1)
30|            rest = m.group(2).split(';')[0].strip()
31|            params = {}
32|            for part in rest.split():
33|                if len(part) >= 2 and part[0] in 'XYZEF':
34|                    try:
35|                        params[part[0]] = float(part[1:])
36|                    except ValueError:
37|                        pass
38|
39|            x = params.get('X')
40|            y = params.get('Y')
41|            z = params.get('Z')
42|            e = params.get('E')
43|
44|            if x is not None and y is not None:
45|                moves.append({
46|                    'cmd': cmd,
47|                    'x': x, 'y': y,
48|                    'z': current_z,
49|                    'e': e if e is not None else current_e,
50|                    'extrude': cmd == 'G1' and e is not None and abs(e) > 0.001,
51|                })
52|            if z is not None:
53|                current_z = z
54|            if e is not None:
55|                current_e = e
56|
57|    travel_dist = sum(
58|        ((m2['x'] - m1['x'])**2 + (m2['y'] - m1['y'])**2)**0.5
59|        for m1, m2 in zip(moves[:-1], moves[1:])
60|        if m2.get('extrude') and m1.get('extrude')
61|    )
62|
63|    return moves, {'total_moves': len(moves), 'travel_dist_mm': round(travel_dist, 1)}
