66|def build_layer_data(moves: list[dict], max_sample_layers: int = 48) -> list[dict]:
67|    """Group moves into per-layer print segments, sample for display."""
68|    layers = {}
69|    for m in moves:
70|        z_key = round(m['z'], 2)
71|        if z_key not in layers:
72|            layers[z_key] = []
73|        layers[z_key].append(m)
74|
75|    z_vals = sorted(layers.keys())
76|    # Sample evenly across all layers
77|    step = max(1, len(z_vals) // max_sample_layers)
78|    sampled_z = z_vals[::step]
79|
80|    all_layers = []
81|    for z in sampled_z:
82|        pts = [m for m in layers[z] if m.get('extrude')]
83|        if len(pts) > 1:
84|            flat = []
85|            for p in pts:
86|                flat.extend([round(p['x'], 1), round(p['y'], 1)])
87|            all_layers.append({'z': round(z, 2), 'pts': flat[:400]})  # cap
88|
89|    return all_layers
