122|  {stats['total_moves']} moves · <span id="layer-label">layer 1</span>
123|</div>
124|<div id="stats">{stats['travel_dist_mm']}m total travel</div>
125|<div class="controls">
126|  <button id="play-btn">▶ Play</button>
127|  <button id="reset-btn">⟲ Reset</button>
128|</div>
