130|<script type="importmap">
131|{{
132|  "imports": {{
133|    "three": "https://cdn.jsdelivr.net/npm/three@0.160.0/build/three.module.js",
134|    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/"
135|  }}
