139|<script type="module">
140|import * as THREE from 'three';
141|import {{ OrbitControls }} from 'three/addons/controls/OrbitControls.js';
142|
143|const LAYER_COLORS = [0x58a6ff, 0x3fb950, 0xd29922, 0xf78166, 0xbc8cff, 0x79c0ff, 0x56d364, 0xe3b341, 0xffa657, 0xd2a8ff];
144|const layerData = {data_json};
145|
146|// Scene
147|const scene = new THREE.Scene();
148|scene.background = new THREE.Color(0x0d1117);
149|
150|const camera = new THREE.PerspectiveCamera(45, window.innerWidth/window.innerHeight, 1, 100000);
151|camera.position.set(4000, 3000, 5000);
152|
153|const renderer = new THREE.WebGLRenderer({{ antialias: true }});
154|renderer.setSize(window.innerWidth, window.innerHeight);
155|renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
156|document.body.appendChild(renderer.domElement);
157|
158|const controls = new OrbitControls(camera, renderer.domElement);
159|controls.target.set(2500, 0, 200);
160|controls.enableDamping = true;
161|controls.dampingFactor = 0.08;
162|controls.maxPolarAngle = Math.PI / 2.1;
163|
164|// Grid
165|const gridHelper = new THREE.GridHelper(6000, 20, 0x21262d, 0x21262d);
166|gridHelper.position.y = 0;
167|scene.add(gridHelper);
168|
169|// Lights
170|scene.add(new THREE.AmbientLight(0x404660));
171|const dirLight = new THREE.DirectionalLight(0xffffff, 0.8);
172|dirLight.position.set(2000, 5000, 3000);
173|scene.add(dirLight);
174|const backLight = new THREE.DirectionalLight(0x8888ff, 0.3);
175|backLight.position.set(-2000, 1000, -3000);
176|scene.add(backLight);
177|
178|// Build layers
179|const layerLines = [];
180|let allPoints = [];
181|
182|layerData.forEach((ld, idx) => {{
183|  const pts = ld.pts;
184|  if (pts.length < 4) return;
185|  const color = LAYER_COLORS[idx % LAYER_COLORS.length];
186|  const z = ld.z;
187|
188|  const positions = [];
189|  for (let i = 0; i < pts.length; i += 2) {{
190|    positions.push(pts[i], z, pts[i+1]);
191|  }}
192|  if (positions.length < 6) return;
193|
194|  const geometry = new THREE.BufferGeometry();
195|  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
196|  const material = new THREE.LineBasicMaterial({{ color, transparent: true, opacity: 0.3 }});
197|  const line = new THREE.Line(geometry, material);
198|  line.visible = false;
199|  scene.add(line);
200|  layerLines.push({{ line, material, z }});
201|  allPoints.push(...positions);
202|}});
203|
204|// Auto-fit camera to data
205|if (allPoints.length > 0) {{
206|  let minX=Infinity,maxX=-Infinity,minZ=Infinity,maxZ=-Infinity;
207|  for (let i=0; i<allPoints.length; i+=3) {{
208|    minX=Math.min(minX,allPoints[i]); maxX=Math.max(maxX,allPoints[i]);
209|    minZ=Math.min(minZ,allPoints[i+2]); maxZ=Math.max(maxZ,allPoints[i+2]);
210|  }}
211|  const cx = (minX+maxX)/2, cz = (minZ+maxZ)/2;
212|  const span = Math.max(maxX-minX, maxZ-minZ, 1000);
213|  camera.position.set(cx + span*1.2, span*0.8, cz + span*1.5);
214|  controls.target.set(cx, 0, cz);
215|}}
216|
217|layerLines.sort((a,b) => a.z - b.z);
218|
