247|  if (isPlaying) {{
248|    isPlaying = false;
249|    clearInterval(playTimer);
250|    document.getElementById('play-btn').textContent = '▶ Play';
251|    return;
252|  }}
253|  isPlaying = true;
254|  document.getElementById('play-btn').textContent = '⏸ Pause';
255|  showLayer(0);
256|  let i = 0;
